/* == EXEMPLE =======================================
 * Parser un fichier INI (key=value) en struct
 * Même pattern : fgets + sscanf + tableau de struct
 * ================================================= */
typedef struct { char key[32]; char val[32]; } KV;

void example_parse_ini(void) {
    const char *ini = "host=localhost\nport=8080\n";
    FILE *f = fmemopen((void *)ini, strlen(ini), "r");
    if (!f) return;
    char line[128];
    KV entries[10];
    int n = 0;
    while (fgets(line, sizeof(line), f) && n < 10) {
        line[strcspn(line, "\n")] = 0;
        if (sscanf(line, "%31[^=]=%31s", entries[n].key, entries[n].val) == 2)
            n++;
    }
    fclose(f);
    for (int i = 0; i < n; i++)
        printf("%s => %s\n", entries[i].key, entries[i].val);
}
